SELECT id, metadata_key, metadata_value, created_at, updated_at
FROM metadata
LIMIT 5;

SELECT studies.study_name, plant_species.species_name
FROM studies
JOIN plant_species ON studies.id = plant_species.id;

SELECT project_name
FROM projects
WHERE id NOT IN (
  SELECT DISTINCT project_id
  FROM project_collaborators
);

SELECT user_id, GROUP_CONCAT(project_id) AS projects
FROM project_collaborators
GROUP BY user_id;
